INSERT INTO position_categories (id, positionId, name) VALUES (1, 6, 'Görev Bilinci');
INSERT INTO position_categories (id, positionId, name) VALUES (2, 6, 'İletişim Becerisi');
INSERT INTO position_categories (id, positionId, name) VALUES (3, 6, 'Analitik Düşünme ve Problem Çözme');
INSERT INTO position_categories (id, positionId, name) VALUES (4, 6, 'Kalite Odaklılık');
INSERT INTO position_categories (id, positionId, name) VALUES (5, 6, 'Takım Çalışması ve İşbirliği');
INSERT INTO position_categories (id, positionId, name) VALUES (6, 6, 'Yönetim Becerileri');
INSERT INTO position_categories (id, positionId, name) VALUES (7, 6, 'İş Disiplini ve Tutum');
INSERT INTO position_categories (id, positionId, name) VALUES (8, 6, 'Restoran Yönetimi');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (1, 1, 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (1, 2, 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (1, 3, 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (1, 4, 'Ahlaki ve etik değerlere uygun davranır. Davranışlarının sorumluluğunu üstlenir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (2, 5, 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (2, 6, 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (2, 7, 'İşle ilgili konularla ilgili bilgiyi zamanında aktarır ve paylaşır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (2, 8, 'Her türlü iletişimde empati kurmaya özen gösterir.Gerektiğinde iletişim tarzını değiştirebilir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (3, 9, 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (3, 10, 'Durum ve problem karşısında alacağı hareketin sonucunu bilir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (3, 11, 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (3, 12, 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, 13, 'Mevcut düzen ve iş yapma yöntemine uygun çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, 14, 'Kaliteyi belirlenen standartlara göre uyarlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, 15, 'İş yapma yöntemini sürekli geliştirmeye, verimlilik ve etkililiği artırmaya odaklı çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, 16, 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (5, 17, 'Çalışma ortamında iyi ilişkiler kurar ve korur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (5, 18, 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (5, 19, 'Takım arkadaşlarını, ortak başarı için heveslendirir, onları motive eder. "Biz" olgusunu yaygınlaştır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (5, 20, 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 21, 'Doğru insanları belirleyerek ihtiyaçlar doğrultusunda görev dağılımını net bir şekilde yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 22, 'Ekibine mentorluk yapar, yapıcı geri bildirimlerde bulunur ve yönlendirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 23, 'Ekibini motive eder, olumsuzluk yaratacak durumların önüne geçmek için çaba sarf eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 24, 'Ekip içindeki anlaşmazlıkları kişiselleştirmeden şirket yararını gözeterek yönetir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 25, 'İnsanların yeteneklerini keşfeder ve doğru şekilde değerlendirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 26, 'Görevlerin yerine getirilebilmesi için gerekli olan kaynakları belirler ve organize eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 27, 'Aldığı kararların arkasındadır ve bu kararların sorumluluğunu üstlenir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 28, 'Zor durumlarda ve baskı altında en etkili kararı verir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 29, 'Çalışanların gelişimi için öğrenme ortamı yaratır. Ekibini ve kendini sürekli geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, 30, 'Davranışları ile ekibe örnek olur. Söyledikleri ile yaptıkları tutarlıdır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (7, 31, 'Dış görünüşüne dikkat eder. Kurumu ve markayı başarıyla temsil eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (7, 32, 'Şirketin eğitimlerine aktif olarak katılır, çalışanların katılımını sağlar. Eğitim etkinliğini takip eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (7, 33, 'Restoranın KPI''larını bilir, bu hedefleri gerçekleştirmek için gerekli planlamaları yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (7, 34, 'Mazeret bildirmeden işe gelmemezlik yapmaz.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 35, 'Ekibine ve müşterilere karşı güleryüzlü ve naziktir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 36, 'İnsan Kaynakları ve operasyonel prosedür ve talimatları bilir, uygulanmasını sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 37, 'Vardiya planlamalarını verimli bir şekilde yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 38, 'Restoranın nakit ve avans yönetimini hatasız bir şekilde yapar. Prosedürlere uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 39, 'Restoranın stok ve sipariş yönetimini etkin bir şekilde yapar. Fire ve/veya satış kaybına sebep olmaz.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 40, 'Müşteri şikayetlerini prosedürler çerçevesinde müşteri kaybına yol açmayacak şekilde yönetir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 41, 'Menü fiyatları, pormosyon ve kampanyalarla ilgili bilgilidir. Gerektiği gibi uygulamasını yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 42, 'Ürünlerle ve içerikleri ile ilgili bilgilidir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 43, 'Çalışma süresince Gıda Güvenliği ve İSG kurallarına uygun hareket edilmesini sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 44, 'Tüm şube ekipmanlarının özenli ve titiz kullanılmasını sağlar. Temizliklerini yaptırır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 45, 'Restoran düzenini sağlar, dağınık ve kirli bir görüntü verilmesine izin vermez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 46, 'Zor müşteriler ile iletişim kurabilir, gerekli aksiyonu alır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 47, 'Fire ve israfı önler, gerekli önlemleri alır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 48, 'Tüm çalışma alanlarının (servis, ızgara, kasa, depo) temizliğini ve hijyenini sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 49, 'Bulunduğu şubeye özel satışı arttıracak alternatif öneriler sunar. Müşteri geri bildirimlerini paylaşır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, 50, 'Pazarlama departmanından gelen görsel ve kampanyaları doğru ve eksiksiz bir biçimde uygular.');

